import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Sparkles, Library, Clock, BookOpen, Plus, X, Star, Upload, Trash2, AlertCircle, Calendar, Play, Square } from 'lucide-react';
import { useProgressStore, Keepsake, MediaType } from '../store/progressStore';
import MediaCard from './MediaCard';
import { containerVariants } from '../constants';

const KeepsakesTab: React.FC = () => {
  const { keepsakes, addKeepsake, updateKeepsake, removeKeepsake, addActivityLog } = useProgressStore();
  const [activeTab, setActiveTab] = useState<'ALL' | MediaType>('ALL');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- IMMERSION TIMER STATE ---
  const [isTimerRunning, setIsTimerRunning] = useState(false);
  const [sessionSeconds, setSessionSeconds] = useState(0);
  const [totalImmersionSeconds, setTotalImmersionSeconds] = useState(0);

  useEffect(() => {
    const savedTime = localStorage.getItem('immersion_total_time');
    if (savedTime) setTotalImmersionSeconds(parseInt(savedTime, 10));
  }, []);

  useEffect(() => {
    let interval: any;
    if (isTimerRunning) {
      interval = setInterval(() => {
        setSessionSeconds(prev => prev + 1);
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [isTimerRunning]);

  const toggleTimer = () => {
    if (isTimerRunning) {
      // Stop & Log
      if (sessionSeconds >= 60) {
        addActivityLog({
          timestamp: Date.now(),
          category: 'IMMERSION',
          durationMinutes: Math.floor(sessionSeconds / 60),
          summary: 'Active Immersion Session (Timer)'
        });
      }
      const newTotal = totalImmersionSeconds + sessionSeconds;
      setTotalImmersionSeconds(newTotal);
      localStorage.setItem('immersion_total_time', newTotal.toString());
      window.dispatchEvent(new Event('storage-update'));
      setSessionSeconds(0);
      setIsTimerRunning(false);
    } else {
      setIsTimerRunning(true);
    }
  };

  const formatTime = (secs: number) => {
    const mins = Math.floor(secs / 60);
    const s = secs % 60;
    return `${mins.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  // --- Modal Form State ---
  const [editingId, setEditingId] = useState<string | null>(null);
  const [confirmDelete, setConfirmDelete] = useState(false);

  const [newTitle, setNewTitle] = useState('');
  const [newType, setNewType] = useState<MediaType>('ANIME');
  const [newCover, setNewCover] = useState('');
  const [newRating, setNewRating] = useState(5);
  const [newMetric, setNewMetric] = useState('');
  const [newDateCompleted, setNewDateCompleted] = useState('');
  const [newCaption, setNewCaption] = useState('');

  // --- Filter Logic ---
  const filteredItems = activeTab === 'ALL' 
    ? keepsakes 
    : keepsakes.filter(item => item.type === activeTab);

  const calculateStats = () => {
    let totalHours = 0;
    let totalVolumes = 0;
    keepsakes.forEach(item => {
      if (item.type === 'MANGA') totalVolumes += item.durationOrVolumes || 0;
      else totalHours += (item.durationOrVolumes || 0) / 60;
    });
    // Add timer hours to titles total
    totalHours += totalImmersionSeconds / 3600;
    return { hours: Math.round(totalHours), volumes: totalVolumes, titles: keepsakes.length };
  };

  const currentStats = calculateStats();
  const stats = [
    { label: 'Hours', value: currentStats.hours.toString(), icon: Clock },
    { label: 'Volumes', value: currentStats.volumes.toString(), icon: BookOpen },
    { label: 'Titles', value: currentStats.titles.toString(), icon: Library },
  ];

  const tabs = [
    { id: 'ALL', label: 'All' },
    { id: 'ANIME', label: 'Anime' },
    { id: 'MANGA', label: 'Manga' },
    { id: 'GAME', label: 'Games' },
    { id: 'SHOW', label: 'Shows' },
  ];

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setNewCover(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const resetForm = () => {
    setEditingId(null);
    setConfirmDelete(false);
    setNewTitle('');
    setNewType('ANIME');
    setNewCover('');
    setNewRating(5);
    setNewMetric('');
    setNewDateCompleted(new Date().toISOString().split('T')[0]);
    setNewCaption('');
  };

  const openAddModal = () => { resetForm(); setIsModalOpen(true); };
  const openEditModal = (id: string) => {
    const item = keepsakes.find(k => k.id === id);
    if (!item) return;
    setEditingId(id);
    setConfirmDelete(false);
    setNewTitle(item.title);
    setNewType(item.type);
    setNewCover(item.coverUrl);
    setNewRating(item.rating);
    setNewMetric(item.durationOrVolumes.toString());
    setNewDateCompleted(item.dateCompleted || item.dateAdded);
    setNewCaption(item.caption);
    setIsModalOpen(true);
  };

  const handleRemove = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (!editingId) return;
    if (!confirmDelete) { setConfirmDelete(true); return; }
    removeKeepsake(editingId);
    setIsModalOpen(false);
    resetForm();
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const commonData = {
      title: newTitle,
      type: newType,
      coverUrl: newCover || 'https://via.placeholder.com/300x400?text=No+Cover',
      rating: newRating,
      caption: newCaption,
      durationOrVolumes: Number(newMetric) || 0,
      dateCompleted: newDateCompleted,
    };
    if (editingId) updateKeepsake(editingId, commonData);
    else {
      const newItem: Keepsake = {
        id: crypto.randomUUID(),
        ...commonData,
        dateAdded: new Date().toISOString().split('T')[0]
      };
      addKeepsake(newItem);
    }
    setIsModalOpen(false);
    resetForm();
  };

  return (
    <motion.div variants={containerVariants} initial="hidden" animate="visible" className="p-6 lg:p-8 w-full max-w-7xl mx-auto min-h-full flex flex-col">
      {/* HEADER SECTION */}
      <div className="flex flex-col xl:flex-row justify-between items-start xl:items-end mb-8 border-b pb-6 gap-6 border-coquette-gold/30">
        <div className="flex-1 w-full">
           <div className="flex items-center gap-3 mb-2">
              <div className="p-2 rounded-full bg-pink-50 text-coquette-accent"><Sparkles className="w-5 h-5" /></div>
              <h1 className="text-3xl lg:text-4xl font-bold font-coquette-header text-coquette-text">My Keepsakes</h1>
           </div>
           <div className="flex flex-col md:flex-row md:items-center gap-4 pl-12">
             <p className="text-sm font-coquette-body text-coquette-subtext italic">A treasured archive of the worlds I've explored.</p>
             <div className="hidden md:block w-px h-4 bg-coquette-border"></div>
             <div className="flex flex-wrap gap-2">
               {tabs.map(tab => (
                  <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`px-4 py-1.5 rounded-full text-xs font-bold tracking-wider transition-all relative overflow-hidden ${activeTab === tab.id ? 'bg-coquette-accent text-white shadow-md' : 'bg-white text-gray-400 hover:text-coquette-text border border-transparent hover:border-coquette-border'}`}>
                    {tab.label}
                  </button>
               ))}
             </div>
           </div>
        </div>

        {/* COMPACT STATS & IMMERSION TIMER */}
        <div className="flex items-center gap-4 self-center xl:self-end">
          {/* Active Immersion Timer */}
          <div className="mr-2 flex flex-col items-end">
            <span className="text-[9px] font-bold text-coquette-subtext uppercase tracking-widest mb-1">Immersion Timer</span>
            <button
              onClick={toggleTimer}
              className={`flex items-center gap-2 px-3 py-1.5 rounded-full font-bold text-xs transition-all shadow-sm ${isTimerRunning ? 'bg-emerald-50 text-emerald-500 border border-emerald-200 animate-pulse' : 'bg-white border border-gray-200 text-gray-400 hover:bg-emerald-50 hover:text-emerald-500'}`}
            >
              {isTimerRunning ? <><Square className="w-3 h-3 fill-current" /> <span className="font-mono">{formatTime(sessionSeconds)}</span></> : <><Play className="w-3 h-3 fill-current" /> <span>Start</span></>}
            </button>
          </div>

          {stats.map((stat, idx) => (
             <div key={idx} className="w-16 h-16 lg:w-20 lg:h-20 rounded-full flex flex-col items-center justify-center relative border bg-white border-dashed border-coquette-gold/30 shadow-sm">
                <div className="absolute -top-2 p-1 rounded-full border bg-white border-coquette-gold/30 text-coquette-gold"><stat.icon className="w-2.5 h-2.5" /></div>
                <span className="text-lg lg:text-xl font-bold leading-none mt-1 font-coquette-header text-coquette-text">{stat.value}</span>
                <span className="text-[8px] lg:text-[9px] uppercase tracking-widest mt-1 text-coquette-subtext">{stat.label}</span>
             </div>
          ))}
          <button onClick={openAddModal} className="w-16 h-16 lg:w-20 lg:h-20 rounded-full flex flex-col items-center justify-center transition-all duration-300 bg-coquette-accent hover:bg-[#ff9eb0] text-white shadow-lg"><Plus className="w-6 h-6 lg:w-8 lg:h-8" /><span className="text-[8px] lg:text-[9px] font-bold uppercase mt-1">Add</span></button>
        </div>
      </div>

      {/* GRID */}
      <AnimatePresence mode='popLayout'>
        <motion.div key={activeTab} initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -20 }} className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 pb-20 auto-rows-fr">
          {filteredItems.map((item) => <MediaCard key={item.id} item={item} onEdit={openEditModal} />)}
        </motion.div>
      </AnimatePresence>

      {/* MODAL */}
      <AnimatePresence>
        {isModalOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={() => setIsModalOpen(false)} />
            <motion.div initial={{ scale: 0.9, opacity: 0, y: 20 }} animate={{ scale: 1, opacity: 1, y: 0 }} exit={{ scale: 0.9, opacity: 0, y: 20 }} className="relative w-full max-w-lg rounded-[30px] p-8 shadow-2xl overflow-hidden bg-[#fffcfc] border border-coquette-gold/30">
               <div className="flex justify-between items-center mb-6"><h2 className="text-2xl font-bold font-coquette-header text-coquette-text">{editingId ? 'Edit Memory' : 'Log a New Memory'}</h2><button onClick={() => setIsModalOpen(false)} className="text-gray-400 hover:text-gray-600"><X className="w-6 h-6" /></button></div>
               <form onSubmit={handleSave} className="space-y-5">
                 <div><label className="block text-xs font-bold uppercase tracking-wider mb-2 text-coquette-subtext">Title</label><input type="text" required value={newTitle} onChange={e => setNewTitle(e.target.value)} className="w-full p-3 rounded-xl border focus:outline-none focus:ring-2 transition-all bg-white border-gray-200 text-coquette-text focus:border-coquette-accent" /></div>
                 <div className="grid grid-cols-2 gap-4">
                    <div><label className="block text-xs font-bold uppercase tracking-wider mb-2 text-coquette-subtext">Category</label><select value={newType} onChange={e => setNewType(e.target.value as MediaType)} className="w-full p-3 rounded-xl border focus:outline-none focus:ring-2 transition-all appearance-none bg-white border-gray-200 text-coquette-text focus:border-coquette-accent"><option value="ANIME">Anime</option><option value="MANGA">Manga</option><option value="GAME">Game</option><option value="SHOW">Show</option></select></div>
                    <div><label className="block text-xs font-bold uppercase tracking-wider mb-2 text-coquette-subtext">Rating</label><div className="flex gap-1 items-center h-[46px]">{[1, 2, 3, 4, 5].map(star => (<button type="button" key={star} onClick={() => setNewRating(star)} className={`transition-colors ${star <= newRating ? 'text-coquette-gold' : 'text-gray-300'}`}><Star className="w-6 h-6 fill-current" /></button>))}</div></div>
                 </div>
                 <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div><label className="block text-xs font-bold uppercase tracking-wider mb-2 text-coquette-subtext">Cover Photo</label><div onClick={() => fileInputRef.current?.click()} className="relative w-full h-[50px] rounded-xl border border-dashed flex items-center justify-center cursor-pointer transition-all hover:bg-black/5 overflow-hidden bg-white border-coquette-gold/50 text-coquette-text"><input type="file" ref={fileInputRef} accept="image/*" onChange={handleImageUpload} className="hidden" />{newCover ? <div className="flex items-center gap-2 px-3 w-full"><img src={newCover} alt="Preview" className="w-8 h-8 rounded object-cover border" /><span className="text-xs truncate flex-1">Image Selected</span><button type="button" onClick={(e) => { e.stopPropagation(); setNewCover(''); }} className="p-1 hover:bg-black/10 rounded-full"><X className="w-3 h-3" /></button></div> : <div className="flex items-center gap-2 text-xs opacity-70"><Upload className="w-4 h-4" /><span>Upload Image</span></div>}</div></div>
                    <div><label className="block text-xs font-bold uppercase tracking-wider mb-2 text-coquette-subtext">{newType === 'MANGA' ? 'Volumes Read' : 'Duration (Mins)'}</label><input type="number" required value={newMetric} onChange={e => setNewMetric(e.target.value)} className="w-full p-3 rounded-xl border focus:outline-none focus:ring-2 transition-all bg-white border-gray-200 text-coquette-text focus:border-coquette-accent" /></div>
                 </div>
                 <div><label className="block text-xs font-bold uppercase tracking-wider mb-2 text-coquette-subtext">Date Completed</label><div className="relative"><input type="date" required value={newDateCompleted} onChange={e => setNewDateCompleted(e.target.value)} className="w-full p-3 rounded-xl border focus:outline-none focus:ring-2 transition-all bg-white border-gray-200 text-coquette-text focus:border-coquette-accent" /><Calendar className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 w-5 h-5 pointer-events-none" /></div></div>
                 <div><div className="flex justify-between items-center mb-2"><label className="block text-xs font-bold uppercase tracking-wider text-coquette-subtext">One-Liner Review</label><span className={`text-[10px] ${newCaption.length > 75 ? 'text-red-500' : 'text-gray-400'}`}>{newCaption.length}/75</span></div><textarea rows={2} required maxLength={75} value={newCaption} onChange={e => setNewCaption(e.target.value)} placeholder="Write a sweet note..." className="w-full p-3 rounded-xl border focus:outline-none focus:ring-2 transition-all resize-none bg-white border-gray-200 text-coquette-text focus:border-coquette-accent" /></div>
                 <div className="flex gap-4 pt-2">
                    {editingId && (<button type="button" onClick={handleRemove} className={`px-4 py-4 rounded-xl border transition-all duration-200 flex items-center justify-center gap-2 min-w-[60px] ${confirmDelete ? 'bg-red-500 text-white border-red-500' : 'border-red-200 text-red-400 hover:bg-red-50'}`}>{confirmDelete ? <AlertCircle className="w-5 h-5" /> : <Trash2 className="w-5 h-5" />}</button>)}
                    <button type="submit" className="flex-1 py-4 rounded-xl font-bold tracking-wide transition-all shadow-lg bg-coquette-accent text-white hover:bg-[#ff9eb0]">{editingId ? 'Update Entry' : 'Save to Collection'}</button>
                 </div>
               </form>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </motion.div>
  );
};

