import React, { useState, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Download, Upload, Database, Check, AlertCircle, FileJson, RefreshCw, Save } from 'lucide-react';

interface DataManagementModalProps {
  isOpen: boolean;
  onClose: () => void;
}

// The complete list of keys to backup/restore
const TARGET_KEYS = [
  'nihongo-nexus-storage', // Zustand Store (Stats, Keepsakes, Logs, Calendar)
  'messenger_contacts',    // Personas
  'messenger_history',     // Chat Logs
  'messenger_total_time',  // Study Timer
  'grammar_total_time',    // Study Timer
  'anki_total_time',       // Study Timer
  'immersion_total_time',  // Study Timer
  'mission_scenarios'      // Roleplay Data
];

const DataManagementModal: React.FC<DataManagementModalProps> = ({ isOpen, onClose }) => {
  const [status, setStatus] = useState<'idle' | 'success' | 'error'>('idle');
  const [statusMsg, setStatusMsg] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- EXPORT LOGIC ---
  const handleExport = () => {
    try {
      const backupData: Record<string, any> = {};

      TARGET_KEYS.forEach(key => {
        const raw = localStorage.getItem(key);
        if (raw) {
          try {
            backupData[key] = JSON.parse(raw);
          } catch {
            backupData[key] = raw;
          }
        }
      });

      const payload = {
        meta: {
          app: 'nihongo-nexus',
          version: 1,
          timestamp: new Date().toISOString(),
        },
        data: backupData
      };

      const blob = new Blob([JSON.stringify(payload, null, 2)], { type: 'application/json' });
      const url = URL.createObjectURL(blob);

      const link = document.createElement('a');
      link.href = url;
      link.download = `nexus-backup-${new Date().toISOString().split('T')[0]}.json`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);

      setStatus('success');
      setStatusMsg('Backup generated successfully.');
      setTimeout(() => setStatus('idle'), 3000);
    } catch (e) {
      console.error(e);
      setStatus('error');
      setStatusMsg('Failed to generate backup.');
    }
  };

  // --- IMPORT LOGIC (SMART MERGE) ---
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        if (!json.meta || json.meta.app !== 'nihongo-nexus' || !json.data) {
          throw new Error("Invalid backup file format.");
        }
        performSmartMerge(json.data);
      } catch (e) {
        console.error(e);
        setStatus('error');
        setStatusMsg('Invalid or corrupt backup file.');
      }
    };
    reader.readAsText(file);
  };

  const performSmartMerge = (incomingData: Record<string, any>) => {
    let mergeCount = 0;

    // 1. Handle Simple Timers (Max Value Wins)
    ['messenger_total_time', 'grammar_total_time', 'anki_total_time', 'immersion_total_time'].forEach(key => {
        if (incomingData[key]) {
            const current = Number(localStorage.getItem(key) || 0);
            const incoming = Number(incomingData[key]);
            if (!isNaN(incoming) && incoming > current) {
                localStorage.setItem(key, incoming.toString());
                mergeCount++;
            }
        }
    });

    // 2. Handle Messenger Objects (Merge Keys)
    if (incomingData['messenger_contacts']) {
        const current = JSON.parse(localStorage.getItem('messenger_contacts') || '{}');
        const merged = { ...current, ...incomingData['messenger_contacts'] };
        localStorage.setItem('messenger_contacts', JSON.stringify(merged));
        mergeCount++;
    }

    if (incomingData['messenger_history']) {
        const current = JSON.parse(localStorage.getItem('messenger_history') || '{}');
        const incoming = incomingData['messenger_history'];
        Object.keys(incoming).forEach(contactId => {
            const currentMsgs = current[contactId] || [];
            const incomingMsgs = incoming[contactId] || [];
            const msgMap = new Map();
            currentMsgs.forEach((m: any) => msgMap.set(m.id, m));
            incomingMsgs.forEach((m: any) => msgMap.set(m.id, m));
            current[contactId] = Array.from(msgMap.values()).sort((a: any, b: any) => 
               (a.timestamp || 0) > (b.timestamp || 0) ? 1 : -1
            );
        });
        localStorage.setItem('messenger_history', JSON.stringify(current));
        mergeCount++;
    }

    // 3. Handle Zustand Store (Complex Nested Merge)
    if (incomingData['nihongo-nexus-storage']) {
        const rawCurrent = localStorage.getItem('nihongo-nexus-storage');
        const currentObj = rawCurrent ? JSON.parse(rawCurrent) : { state: {} };
        const incomingObj = incomingData['nihongo-nexus-storage'];
        const incomingState = typeof incomingObj === 'string' ? JSON.parse(incomingObj).state : incomingObj.state;
        const currentState = currentObj.state || {};

        if (incomingState) {
            currentState.vocabCount = Math.max(currentState.vocabCount || 0, incomingState.vocabCount || 0);
            currentState.immersionMinutes = Math.max(currentState.immersionMinutes || 0, incomingState.immersionMinutes || 0);
            currentState.grammarPoints = Math.max(currentState.grammarPoints || 0, incomingState.grammarPoints || 0);
            currentState.streak = Math.max(currentState.streak || 0, incomingState.streak || 0);

            ['logs', 'keepsakes'].forEach(arrKey => {
                const currentArr = currentState[arrKey] || [];
                const incomingArr = incomingState[arrKey] || [];
                const map = new Map();
                currentArr.forEach((i: any) => map.set(i.id, i));
                incomingArr.forEach((i: any) => map.set(i.id, i));
                currentState[arrKey] = Array.from(map.values());
            });

            const chapters = new Set([...(currentState.masteredChapters || []), ...(incomingState.masteredChapters || [])]);
            currentState.masteredChapters = Array.from(chapters);

            currentState.completedDates = { ...(currentState.completedDates || {}), ...(incomingState.completedDates || {}) };
            currentState.dailyChecklist = { ...(currentState.dailyChecklist || {}), ...(incomingState.dailyChecklist || {}) };
            currentState.grammarDatabase = { ...(currentState.grammarDatabase || {}), ...(incomingState.grammarDatabase || {}) };

            currentObj.state = currentState;
            localStorage.setItem('nihongo-nexus-storage', JSON.stringify(currentObj));
            mergeCount++;
        }
    }

    setStatus('success');
    setStatusMsg(`Sync Complete. Merged ${mergeCount} data clusters.`);
    setTimeout(() => { window.location.reload(); }, 1500);
  };

  if (!isOpen) return null;

  return (
    <AnimatePresence>
      <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
        <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="absolute inset-0 bg-black/50 backdrop-blur-sm" onClick={onClose} />
        <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} exit={{ scale: 0.9, opacity: 0 }} className="relative w-full max-w-lg bg-[#fffcfc] rounded-[30px] shadow-2xl overflow-hidden border border-rose-200">
          <div className="p-6 border-b border-rose-100 bg-rose-50/50 flex items-center justify-between">
            <div className="flex items-center gap-3">
               <div className="p-2 bg-white rounded-full border border-rose-100 text-rose-500 shadow-sm"><Database className="w-5 h-5" /></div>
               <div><h2 className="text-xl font-bold font-coquette-header text-gray-800">Data Vault</h2><p className="text-xs text-rose-400 font-bold uppercase tracking-wider">Backup & Restore</p></div>
            </div>
            <button onClick={onClose} className="p-2 rounded-full hover:bg-white text-gray-400 hover:text-rose-400 transition-colors"><X className="w-5 h-5" /></button>
          </div>
          <div className="p-8 space-y-8">
             {status !== 'idle' && (<motion.div initial={{ opacity: 0, y: -10 }} animate={{ opacity: 1, y: 0 }} className={`p-4 rounded-xl flex items-center gap-3 text-sm font-bold shadow-sm ${status === 'success' ? 'bg-green-50 text-green-600 border border-green-200' : 'bg-red-50 text-red-500 border border-red-200'}`}>{status === 'success' ? <Check className="w-5 h-5" /> : <AlertCircle className="w-5 h-5" />}{statusMsg}{status === 'success' && <RefreshCw className="w-4 h-4 animate-spin ml-auto" />}</motion.div>)}
             <div className="grid grid-cols-2 gap-6">
                <button onClick={handleExport} className="group flex flex-col items-center justify-center p-6 rounded-2xl border-2 border-rose-100 bg-white hover:border-rose-300 hover:shadow-lg transition-all duration-300 gap-4"><div className="w-16 h-16 rounded-full bg-rose-50 flex items-center justify-center text-rose-400 group-hover:scale-110 transition-transform"><Download className="w-8 h-8" /></div><div className="text-center"><h3 className="font-bold text-gray-700 font-coquette-body text-lg">Download Backup</h3><p className="text-xs text-gray-400 mt-1">Save your progress to a file</p></div></button>
