          durationMinutes: Math.floor(sessionSeconds / 60),
          summary: 'Active Immersion Session (Timer)'
        });
      }
      const newTotal = totalImmersionSeconds + sessionSeconds;
      setTotalImmersionSeconds(newTotal);
      localStorage.setItem('immersion_total_time', newTotal.toString());
      window.dispatchEvent(new Event('storage-update'));
      setSessionSeconds(0);
      setIsTimerRunning(false);
    } else {
      setIsTimerRunning(true);
    }
