import { useProgressStore, Keepsake, MediaType } from '../store/progressStore';
import MediaCard from './MediaCard';
import { containerVariants } from '../constants';

const KeepsakesTab: React.FC = () => {
  const { keepsakes, addKeepsake, updateKeepsake, removeKeepsake, addActivityLog } = useProgressStore();
  const [activeTab, setActiveTab] = useState<'ALL' | MediaType>('ALL');
  const [isModalOpen, setIsModalOpen] = useState(false);

  // --- IMMERSION TIMER STATE ---
  const [isTimerRunning, setIsTimerRunning] = useState(false);
  const [sessionSeconds, setSessionSeconds] = useState(0);
  const [totalImmersionSeconds, setTotalImmersionSeconds] = useState(0);

  useEffect(() => {
    const savedTime = localStorage.getItem('immersion_total_time');
    if (savedTime) setTotalImmersionSeconds(parseInt(savedTime, 10));
  }, []);

  useEffect(() => {
    let interval: any;
    if (isTimerRunning) {
      interval = setInterval(() => {
        setSessionSeconds(prev => prev + 1);
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [isTimerRunning]);

  const toggleTimer = () => {
    if (isTimerRunning) {
      // Stop & Log
      if (sessionSeconds >= 60) {
        addActivityLog({
          timestamp: Date.now(),
          category: 'IMMERSION',
          durationMinutes: Math.floor(sessionSeconds / 60),
          summary: 'Active Immersion Session (Timer)'
        });
      }
      const newTotal = totalImmersionSeconds + sessionSeconds;
      setTotalImmersionSeconds(newTotal);
      localStorage.setItem('immersion_total_time', newTotal.toString());
      window.dispatchEvent(new Event('storage-update'));
      setSessionSeconds(0);
      setIsTimerRunning(false);
    } else {
      setIsTimerRunning(true);
    }
  };

  const formatTime = (secs: number) => {
    const mins = Math.floor(secs / 60);
    const s = secs % 60;
    return `${mins.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

