                 <div><div className="flex justify-between items-center mb-2"><label className="block text-xs font-bold uppercase tracking-wider text-coquette-subtext">One-Liner Review</label><span className={`text-[10px] ${newCaption.length > 75 ? 'text-red-500' : 'text-gray-400'}`}>{newCaption.length}/75</span></div><textarea rows={2} required maxLength={75} value={newCaption} onChange={e => setNewCaption(e.target.value)} placeholder="Write a sweet note..." className="w-full p-3 rounded-xl border focus:outline-none focus:ring-2 transition-all resize-none bg-white border-gray-200 text-coquette-text focus:border-coquette-accent" /></div>
                 <div className="flex gap-4 pt-2">
                    {editingId && (<button type="button" onClick={handleRemove} className={`px-4 py-4 rounded-xl border transition-all duration-200 flex items-center justify-center gap-2 min-w-[60px] ${confirmDelete ? 'bg-red-500 text-white border-red-500' : 'border-red-200 text-red-400 hover:bg-red-50'}`}>{confirmDelete ? <AlertCircle className="w-5 h-5" /> : <Trash2 className="w-5 h-5" />}</button>)}
                    <button type="submit" className="flex-1 py-4 rounded-xl font-bold tracking-wide transition-all shadow-lg bg-coquette-accent text-white hover:bg-[#ff9eb0]">{editingId ? 'Update Entry' : 'Save to Collection'}</button>
                 </div>
               </form>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </motion.div>
  );
};

