            <span className="text-[9px] font-bold text-coquette-subtext uppercase tracking-widest mb-1">Immersion Timer</span>
            <button
              onClick={toggleTimer}
              className={`flex items-center gap-2 px-4 py-2 rounded-full font-bold text-xs transition-all shadow-sm border ${isTimerRunning ? 'bg-emerald-50 text-emerald-500 border-emerald-200 animate-pulse' : 'bg-white border-gray-200 text-gray-400 hover:bg-emerald-50 hover:text-emerald-500'}`}
            >
              {isTimerRunning ? <><Square className="w-3 h-3 fill-current" /> <span className="font-mono">{formatTime(displaySeconds)}</span></> : <><Play className="w-3 h-3 fill-current" /> <span>Start</span></>}
            </button>
          </div>

          {stats.map((stat, idx) => (
             <div key={idx} className="w-16 h-16 lg:w-20 lg:h-20 rounded-full flex flex-col items-center justify-center relative border bg-white border-dashed border-coquette-gold/30 shadow-sm flex-shrink-0">
                <div className="absolute -top-2 p-1 rounded-full border bg-white border-coquette-gold/30 text-coquette-gold"><stat.icon className="w-2.5 h-2.5" /></div>
                <span className="text-lg lg:text-xl font-bold leading-none mt-1 font-coquette-header text-coquette-text">{stat.value}</span>
